// Query depth limiting plugin to prevent deeply nested malicious queries
const depthLimitPlugin = {
  requestDidStart() {
    return {
      didResolveOperation({ request, document }) {
        const maxDepth = 5;
        const depth = calculateDepth(document.definitions);
        if (depth > maxDepth) {
          throw new ApolloError(
            `Query depth of ${depth} exceeds maximum allowed depth of ${maxDepth}.`,
            'QUERY_TOO_DEEP'
          );
        }
      }
    };
  }
};

function calculateDepth(definitions, currentDepth = 0) {
  let maxDepth = currentDepth;
  for (const def of definitions) {
    if (def.selectionSet) {
      const childDepth = calculateDepth(def.selectionSet.selections, currentDepth + 1);
      if (childDepth > maxDepth) {
        maxDepth = childDepth;
      }
    }
  }
  return maxDepth;
}

